     1→/**
     2→ * MMS Application Root
     3→ *
     4→ * Main application component that assembles the layout and provides
     5→ * state management context via @belt/tools machine.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.2 Application Layout
     8→ */
     9→
    10→import { Classes, OverlaysProvider } from '@blueprintjs/core';
    11→
    12→import { Header, Toolbar, Sidebar, StatusBar, InfiniteCanvas, ManHourOverlayPanel, DriftOverlayPanel, ScenarioComparisonView, TrainDetailPanel, ModalContainer, ToastManager, AlertBanner } from './components';
    13→import { useUi, useCanvas, useScenario, useFleet } from './store';
    14→import type { UiSliceState } from './store/slices/ui';
    15→import type { CanvasSliceState } from './store/slices/canvas';
    16→import type { ScenarioSliceState } from './store/slices/scenario';
    17→import type { FleetSliceState } from './store/slices/fleet';
    18→
    19→import './App.css';
    20→
    21→function AppContent() {
    22→  const { state: uiStateRaw } = useUi();
    23→  const { state: canvasStateRaw } = useCanvas();
    24→  const { state: scenarioStateRaw } = useScenario();
    25→  const { state: fleetStateRaw } = useFleet();
    26→
    27→  const uiState = uiStateRaw as unknown as UiSliceState;
    28→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    29→  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
    30→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    31→
    32→  // Apply theme class to body
    33→  const themeClass = uiState.theme === 'dark' ? Classes.DARK : '';
    34→
    35→  // Determine if any overlay panels should be visible
    36→  const showManhourPanel = canvasState.layers?.manhourOverlay ?? false;
    37→  const showDriftPanel = canvasState.layers?.driftOverlay ?? false;
    38→  const showScenarioComparison = scenarioState.activeScenarioId && scenarioState.comparisonBaselineId;
    39→  const showTrainDetail = Boolean(fleetState.selectedTrainId);
    40→  const hasRightPanel = showManhourPanel || showDriftPanel || showScenarioComparison || showTrainDetail;
    41→
    42→  return (
    43→    <div className={`mms-app ${themeClass}`} data-testid="mms-app">
    44→      {/* Alert Banner - system-wide notifications */}
    45→      <AlertBanner />
    46→
    47→      {/* Fixed Header */}
    48→      <Header />
    49→
    50→      {/* Main Container (below header) */}
    51→      <div className="mms-main">
    52→        {/* Toolbar */}
    53→        <Toolbar />
    54→
    55→        {/* Content Area */}
    56→        <div className="mms-content">
    57→          {/* Left Sidebar - Train List */}
    58→          <Sidebar />
    59→
    60→          {/* Main Canvas Area */}
    61→          <InfiniteCanvas />
    62→
    63→          {/* Right Overlay Panels */}
    64→          {hasRightPanel && (
    65→            <div className="mms-overlay-panels" style={{
    66→              width: '360px',
    67→              flexShrink: 0,
    68→              display: 'flex',
    69→              flexDirection: 'column',
    70→              gap: '8px',
    71→              padding: '8px',
    72→              backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
    73→              borderLeft: '1px solid var(--pt-divider-color, #e1e8ed)',
    74→              overflowY: 'auto',
    75→            }}>
    76→              {showTrainDetail && <TrainDetailPanel />}
    77→              {showManhourPanel && <ManHourOverlayPanel />}
    78→              {showDriftPanel && <DriftOverlayPanel />}
    79→              {showScenarioComparison && <ScenarioComparisonView />}
    80→            </div>
    81→          )}
    82→        </div>
    83→
    84→        {/* Status Bar */}
    85→        <StatusBar />
    86→      </div>
    87→
    88→      {/* Modal Container - renders active modals */}
    89→      <ModalContainer />
    90→
    91→      {/* Toast Notifications - positioned top-right */}
    92→      <ToastManager />
    93→    </div>
    94→  );
    95→}
    96→
    97→function App() {
    98→  return (
    99→    <OverlaysProvider>
   100→      <AppContent />
   101→    </OverlaysProvider>
   102→  );
   103→}
   104→
   105→export default App;
   106→

